            ContentJson = """{"title":"Purchasing Field Reference","groups":[{"heading":"New Request Form","items":[{"label":"Part (required)","value":"Pick the part you want to buy from a menu. Shows the part number and its description."},{"label":"Quantity (required)","value":"How many you need. Must be at least 1."},{"label":"Required Date (required)","value":"The date you need the part by."},{"label":"Response Deadline (optional)","value":"The date you want vendors to reply by."},{"label":"Description (optional)","value":"General notes about the request."},{"label":"Special Instructions (optional)","value":"Any special handling or quoting requirements."}]},{"heading":"Recording a Vendor's Reply","items":[{"label":"Vendor (required)","value":"Pick the vendor from a menu. Only vendors you asked but haven't heard back from yet appear here. This is the only field you must fill in."},{"label":"Unit Price (optional)","value":"The price per unit the vendor quoted."},{"label":"Lead Time (days) (optional)","value":"How many days the vendor needs to deliver."},{"label":"Minimum Order Quantity (optional)","value":"The smallest amount the vendor will sell at once."},{"label":"Tooling Cost (optional)","value":"Any one-time tooling charge in the quote."},{"label":"Quote Valid Until (optional)","value":"The date the vendor's price stays good until."},{"label":"Notes (optional)","value":"Anything else worth noting about the quote."}]},{"heading":"Sending to Vendors","items":[{"label":"Choose vendors","value":"Pick one or more vendors to ask for a price. Vendors you already asked on this request are left off the list."},{"label":"Send button","value":"Sends your request to the vendors you picked. It's grayed out until you pick at least one. Each vendor is then asked to reply."}]},{"heading":"Request Statuses","items":[{"label":"Draft (gray label)","value":"Created but not yet sent to any vendor. You can still edit it and send it to vendors from here."},{"label":"Sent (blue label