            Tags = """["purchasing","rfq","procurement","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"pu1","text":"You need to buy a part and want competitive quotes. How do you start in Purchasing?","options":[{"id":"a","text":"Create a Purchase Order directly and email it to vendors"},{"id":"b","text":"Click New RFQ, select the part, enter the quantity and required date, and save","isCorrect":true},{"id":"c","text":"Go to Vendors and add a quote to each vendor"},{"id":"d","text":"Record a vendor response first; the RFQ is created automatically"}],"explanation":"Start by creating an RFQ. Click New RFQ, pick the part, enter the quantity and required date (optionally a response deadline, description, and special instructions), and save. The RFQ starts in Draft."},{"id":"pu2","text":"What is the correct RFQ lifecycle?","options":[{"id":"a","text":"Open → Quoted → Closed"},{"id":"b","text":"Draft → Sent → Receiving → Evaluating → Awarded","isCorrect":true},{"id":"c","text":"Pending → Approved → Ordered → Received"},{"id":"d","text":"Created → Submitted → Paid"}],"explanation":"An RFQ starts in Draft, moves to Sent when you send it to vendors, then through Receiving and Evaluating as quotes come in and are compared, and finally to Awarded when you pick a winner. Cancelled and Expired are alternate terminal states."},{"id":"pu3","text":"How do you invite vendors to quote an RFQ?","options":[{"id":"a","text":"Add them as line items in the RFQ create dialog"},{"id":"b","text":"Open the request and choose Send to Vendors, then pick who to ask (vendors you already asked are left off the list)","isCorrect":true},{"id":"c","text":"Vendors are invited automatically based on the part"},{"id":"d","text":"Email them manually; the app does not track invitations"}],"explanation":"Open the request and choose Send to Vendors to pick who to ask. Vendors you already asked are left off the list. Each vendor you pick is then asked to reply. This